import 'package:injectable/injectable.dart'; import 'package:uuid/uuid.dart'; import '../model/pairing_data.dart'; @injectable class QrCodeGenerator { PairingData generate(String ownerUid, String deviceName) => PairingData(deviceId: const Uuid().v4(), deviceName: deviceName, ownerUid: ownerUid, timestamp: DateTime.now().millisecondsSinceEpoch); bool isValid(PairingData data) => !data.isExpired && data.ownerUid.isNotEmpty && data.deviceId.isNotEmpty; }